// Parse Coreradio HTML to extract releases
const html = $input.first().json.body;
const releases = [];

// Primary regex: match shortstory blocks from DLE CMS
const itemRegex = /<div class="shortstory">[\s\S]*?<h2 class="title">[\s\S]*?<a href="([^"]+)">([\s\S]*?)<\/a>[\s\S]*?<\/h2>[\s\S]*?<div class="shortimg">[\s\S]*?<img[^>]+src="([^"]+)"[\s\S]*?<\/div>[\s\S]*?<div class="maincont">([\s\S]*?)<\/div>/g;

let match;
while ((match = itemRegex.exec(html)) !== null) {
  const url = match[1];
  const titleHtml = match[2];
  const imageUrl = match[3];
  const contentHtml = match[4];

  const title = titleHtml.replace(/<[^>]+>/g, '').trim();

  const genreMatch = contentHtml.match(/<b>Genre:<\/b>\s*([^<]+)/);
  const countryMatch = contentHtml.match(/<b>Country:<\/b>\s*([^<]+)/);
  const qualityMatch = contentHtml.match(/<b>Quality:<\/b>\s*([^<]+)/);

  let artist = '', track = '', type = '', year = '';
  const titleMatch = title.match(/^(.+?)\s+-\s+(.+?)\s*(?:\[([^\]]+)\])?\s*\((\d{4})\)/);

  if (titleMatch) {
    [, artist, track, type, year] = titleMatch;
  } else {
    const parts = title.split(' - ');
    if (parts.length >= 2) {
      artist = parts[0];
      track = parts.slice(1).join(' - ');
    } else {
      artist = title;
      track = 'Unknown';
    }
  }

  releases.push({
    json: {
      artist: artist.trim(),
      track: track.trim(),
      type: (type || '').trim(),
      year: year || new Date().getFullYear().toString(),
      genre: genreMatch ? genreMatch[1].trim() : 'Unknown',
      country: countryMatch ? countryMatch[1].trim() : 'Unknown',
      quality: qualityMatch ? qualityMatch[1].trim() : 'Unknown',
      imageUrl: imageUrl,
      sourceUrl: url,
      fullTitle: title,
      scrapedAt: new Date().toISOString()
    }
  });
}

// Fallback: look for Spotify / Apple Music cover art patterns
if (releases.length === 0) {
  const altRegex = /<img[^>]+src="(https:\/\/(?:i\.scdn\.co|is\d+-ssl\.mzstatic\.com)[^"]+)"[^>]*>[\s\S]*?<b>Genre:<\/b>\s*([^<]+)[\s\S]*?<b>Country:<\/b>\s*([^<]+)[\s\S]*?<div[^>]*>([^<]+(?:\[[^\]]+\])?\s*\(\d{4}\))<\/div>/g;

  while ((match = altRegex.exec(html)) !== null) {
    const imageUrl = match[1];
    const genre = match[2].trim();
    const country = match[3].trim();
    const title = match[4].trim();

    let artist = '', track = '', type = '', year = '';
    const titleMatch = title.match(/^(.+?)\s+-\s+(.+?)\s*(?:\[([^\]]+)\])?\s*\((\d{4})\)/);

    if (titleMatch) {
      [, artist, track, type, year] = titleMatch;
    } else {
      const parts = title.split(' - ');
      artist = parts[0] || 'Unknown';
      track = parts.slice(1).join(' - ') || 'Unknown';
    }

    releases.push({
      json: {
        artist: artist.trim(),
        track: track.trim(),
        type: (type || '').trim(),
        year: year || new Date().getFullYear().toString(),
        genre: genre,
        country: country,
        quality: 'MP3, 320 kbps / FLAC',
        imageUrl: imageUrl,
        sourceUrl: 'https://coreradio.online/news/',
        fullTitle: title,
        scrapedAt: new Date().toISOString()
      }
    });
  }
}

return releases;

// Check for favorite bands
const favoriteBands = [
 'vildhjarta', 'allt', 'imminence', 'karmanjakah', 'humanity's last breath', 'invent animate', 'currents', 'lorna shore', 'peur', 'before i turn', 'spiritbox', 'sleep token', 'bring me the horizon'
];

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const searchText = (data.artist + ' ' + data.track + ' ' + data.genre).toLowerCase();

  const isFavorite = favoriteBands.some(band => searchText.includes(band.toLowerCase()));

  results.push({
    json: {
      ...data,
      isFavorite: isFavorite,
      matchReason: isFavorite ? 'Favorite band detected' : 'New release'
    }
  });
}

return results;

